import { ActionResultSimple, RunActionParams } from "@memberjunction/actions-base";
import { RegisterClass } from "@memberjunction/global";
import { BaseFileHandlerAction } from "../utilities/base-file-handler";
import { BaseAction } from '@memberjunction/actions';

/**
 * Action that extracts content from PDF files using pdfjs-dist (Mozilla PDF.js).
 * Can extract text, metadata, or specific pages.
 *
 * Uses pdfjs-dist instead of pdf-parse for broader PDF compatibility,
 * including PDFs generated by pdfkit, and true per-page text extraction.
 *
 * @example
 * ```typescript
 * // Extract all text from PDF
 * await runAction({
 *   ActionName: 'PDF Extractor',
 *   Params: [{
 *     Name: 'FileURL',
 *     Value: 'https://example.com/document.pdf'
 *   }, {
 *     Name: 'ExtractType',
 *     Value: 'text'
 *   }]
 * });
 *
 * // Extract metadata from PDF
 * await runAction({
 *   ActionName: 'PDF Extractor',
 *   Params: [{
 *     Name: 'PDFData',
 *     Value: base64PdfData
 *   }, {
 *     Name: 'ExtractType',
 *     Value: 'metadata'
 *   }]
 * });
 *
 * // Extract specific pages
 * await runAction({
 *   ActionName: 'PDF Extractor',
 *   Params: [{
 *     Name: 'FileID',
 *     Value: 'uuid-of-pdf-file'
 *   }, {
 *     Name: 'ExtractType',
 *     Value: 'pages'
 *   }, {
 *     Name: 'PageNumbers',
 *     Value: [1, 3, 5]
 *   }]
 * });
 * ```
 */
@RegisterClass(BaseAction, "__PDFExtractor")
export class PDFExtractorAction extends BaseFileHandlerAction {

    /**
     * Extracts content from PDF files
     *
     * @param params - The action parameters containing:
     *   - FileID: UUID of MJ Storage file (optional)
     *   - FileURL: URL of PDF file (optional)
     *   - PDFData: Base64 encoded PDF data (optional)
     *   - ExtractType: "text" | "metadata" | "pages" (default: "text")
     *   - PageNumbers: Array of page numbers to extract (for pages extraction)
     *   - MergePages: Boolean - merge text from all pages (default: true)
     *   - IncludePageBreaks: Boolean - add page break markers (default: false)
     *
     * @returns Extracted content based on extraction type
     */
    protected async InternalRunAction(params: RunActionParams): Promise<ActionResultSimple> {
        try {
            const fileContent = await this.getFileContent(params, 'pdfdata', 'fileid', 'fileurl');

            const extractType = (this.getParamValue(params, 'extracttype') || 'text').toLowerCase();
            const pageNumbersParam = this.getParamValue(params, 'pagenumbers');
            const mergePages = this.getBooleanParam(params, 'mergepages', true);
            const includePageBreaks = this.getBooleanParam(params, 'includepagebreaks', false);

            const pdfBuffer = this.toBuffer(fileContent.content, fileContent.source);

            // Lazy-load pdfjs-dist (legacy build works in Node without DOM)
            const pdfjsLib = await import('pdfjs-dist/legacy/build/pdf.mjs');
            const pdfDoc = await pdfjsLib.getDocument({ data: new Uint8Array(pdfBuffer) }).promise as unknown as PDFDocProxy;

            let result: Record<string, unknown>;

            switch (extractType) {
                case 'metadata':
                    result = await this.extractMetadata(pdfDoc);
                    break;
                case 'pages':
                    result = await this.extractPages(pdfDoc, pageNumbersParam, mergePages, includePageBreaks);
                    break;
                case 'text':
                default:
                    result = await this.extractText(pdfDoc, mergePages, includePageBreaks);
                    break;
            }

            pdfDoc.destroy();

            if (extractType === 'text' || extractType === 'pages') {
                params.Params.push({
                    Name: 'ExtractedText',
                    Type: 'Output',
                    Value: result.text
                });
            }

            return {
                Success: true,
                ResultCode: "SUCCESS",
                Message: JSON.stringify({
                    extractType,
                    source: fileContent.source,
                    fileName: fileContent.fileName,
                    ...result
                }, null, 2)
            };

        } catch (error) {
            return {
                Success: false,
                Message: `Failed to extract PDF content: ${error instanceof Error ? error.message : String(error)}`,
                ResultCode: "EXTRACTION_FAILED"
            };
        }
    }

    private toBuffer(content: string | Buffer, source: string): Buffer {
        if (Buffer.isBuffer(content)) return content;
        if (source === 'direct' && this.isBase64(content)) {
            return Buffer.from(content, 'base64');
        }
        return Buffer.from(content, 'binary');
    }

    private isBase64(str: string): boolean {
        try {
            return Buffer.from(str, 'base64').toString('base64') === str;
        } catch {
            return false;
        }
    }

    private async getPageText(pdfDoc: PDFDocProxy, pageNum: number): Promise<string> {
        const page = await pdfDoc.getPage(pageNum);
        const textContent = await page.getTextContent();
        return textContent.items
            .map((item: PDFTextItem) => item.str)
            .join(' ')
            .trim();
    }

    private async extractText(
        pdfDoc: PDFDocProxy,
        mergePages: boolean,
        includePageBreaks: boolean
    ): Promise<Record<string, unknown>> {
        const pageTexts: string[] = [];
        for (let i = 1; i <= pdfDoc.numPages; i++) {
            pageTexts.push(await this.getPageText(pdfDoc, i));
        }

        const separator = includePageBreaks ? '\n\n--- PAGE BREAK ---\n\n' : '\n\n';
        const text = mergePages ? pageTexts.join(separator) : pageTexts.join(separator);

        const metadata = await pdfDoc.getMetadata().catch(() => null);

        return {
            text,
            totalPages: pdfDoc.numPages,
            textLength: text.length,
            info: {
                title: (metadata?.info as Record<string, string>)?.Title ?? null,
                author: (metadata?.info as Record<string, string>)?.Author ?? null,
                subject: (metadata?.info as Record<string, string>)?.Subject ?? null,
                creator: (metadata?.info as Record<string, string>)?.Creator ?? null
            }
        };
    }

    private async extractMetadata(pdfDoc: PDFDocProxy): Promise<Record<string, unknown>> {
        const metadata = await pdfDoc.getMetadata().catch(() => null);
        const info = (metadata?.info ?? {}) as Record<string, string>;

        // Get total text length by extracting all pages
        let totalTextLength = 0;
        for (let i = 1; i <= pdfDoc.numPages; i++) {
            const pageText = await this.getPageText(pdfDoc, i);
            totalTextLength += pageText.length;
        }

        return {
            metadata: {
                ...info,
                pageCount: pdfDoc.numPages
            },
            documentInfo: {
                title: info.Title ?? null,
                author: info.Author ?? null,
                subject: info.Subject ?? null,
                keywords: info.Keywords ?? null,
                creator: info.Creator ?? null,
                producer: info.Producer ?? null,
                creationDate: info.CreationDate ?? null,
                modificationDate: info.ModDate ?? null
            },
            statistics: {
                totalPages: pdfDoc.numPages,
                totalTextLength
            }
        };
    }

    private async extractPages(
        pdfDoc: PDFDocProxy,
        pageNumbersParam: string | undefined,
        mergePages: boolean,
        includePageBreaks: boolean
    ): Promise<Record<string, unknown>> {
        let pageNumbers = this.parsePageNumbers(pageNumbersParam);

        // Validate page numbers
        pageNumbers = pageNumbers.filter(n => n > 0 && n <= pdfDoc.numPages);
        if (pageNumbers.length === 0) {
            throw new Error('No valid page numbers specified');
        }

        const pageTexts: string[] = [];
        for (const pageNum of pageNumbers) {
            pageTexts.push(await this.getPageText(pdfDoc, pageNum));
        }

        const separator = includePageBreaks ? '\n\n--- PAGE BREAK ---\n\n' : '\n\n';
        const text = pageTexts.join(separator);

        return {
            text,
            requestedPages: pageNumbers,
            totalPages: pdfDoc.numPages,
            textLength: text.length
        };
    }

    private parsePageNumbers(param: string | undefined): number[] {
        if (!param) return [];
        if (Array.isArray(param)) {
            return param.map(n => parseInt(String(n))).filter(n => !isNaN(n));
        }
        if (typeof param === 'string') {
            return param.split(',').map(n => parseInt(n.trim())).filter(n => !isNaN(n));
        }
        const parsed = parseInt(String(param));
        return isNaN(parsed) ? [] : [parsed];
    }
}

// Type alias — pdfjs-dist is lazy-loaded so we define a minimal structural type
// that matches the subset of PDFDocumentProxy we use.
// Using a structural type avoids importing from pdfjs-dist at the top level.
type PDFDocProxy = {
    numPages: number;
    getPage(pageNumber: number): Promise<PDFPageProxy>;
    getMetadata(): Promise<{ info: unknown; metadata: unknown }>;
    destroy(): void;
};

type PDFPageProxy = {
    getTextContent(): Promise<{ items: PDFTextItem[] }>;
};

type PDFTextItem = {
    str: string;
};
